import{_ as n,o as a,c as p,ak as l}from"./chunks/framework.DwHlt8HN.js";const h=JSON.parse('{"title":"数据结构与算法","description":"","frontmatter":{},"headers":[],"relativePath":"cs/algorithm/index.md","filePath":"cs/algorithm/index.md","lastUpdated":1774320699000}'),e={name:"cs/algorithm/index.md"};function r(i,s,t,c,o,d){return a(),p("div",null,[...s[0]||(s[0]=[l(`<h1 id="数据结构与算法" tabindex="-1">数据结构与算法 <a class="header-anchor" href="#数据结构与算法" aria-label="Permalink to “数据结构与算法”">​</a></h1><p>程序员的内功修炼，面试战场的硬通货。</p><p>很多人学算法是为了应付面试，刷完 LeetCode 几百道题就去投简历了。但这其实本末倒置——真正的高手，算法是他们的思维方式，而不是临时抱佛脚的速成课。</p><p>算法的核心不是「背答案」，而是<strong>理解每种数据结构背后的设计意图，和每种算法的时空复杂度权衡</strong>。当你理解了数组为什么查询快而插入慢、链表为什么相反、哈希表又是怎么在这两者之间找到平衡点的，你就不再是「刷题机器」，而是真正懂得用算法思维解决问题的人。</p><p>这篇文章系列覆盖常见数据结构（数组、链表、树、图、哈希表）、基础算法（排序、查找、递归、动态规划）、高频面试题型解析，以及工程中的算法应用场景。无论你是准备面试，还是想系统性地夯实算法基础，都能找到有价值的内容。</p><h2 id="模块速览" tabindex="-1">模块速览 <a class="header-anchor" href="#模块速览" aria-label="Permalink to “模块速览”">​</a></h2><p>算法知识体系庞大，但核心脉络其实很清晰——数据结构是「武器」，算法是「战术」，复杂度分析是「判断力」。</p><table tabindex="0"><thead><tr><th>方向</th><th>核心内容</th></tr></thead><tbody><tr><td><strong>基础数据结构</strong></td><td>数组、链表、栈、队列、哈希表、堆、并查集、Trie</td></tr><tr><td><strong>树与图</strong></td><td>二叉树、BST、AVL、红黑树、B/B+ 树、图遍历、最短路、最小生成树</td></tr><tr><td><strong>排序与查找</strong></td><td>八大排序算法、二分查找及其变体</td></tr><tr><td><strong>高级算法</strong></td><td>递归与回溯、分治、贪心、动态规划、单调栈、位运算</td></tr><tr><td><strong>面试高频题型</strong></td><td>两数之和、合并区间、LRU/LFU、最长公共子串、Top-K</td></tr></tbody></table><h2 id="学习路径建议" tabindex="-1">学习路径建议 <a class="header-anchor" href="#学习路径建议" aria-label="Permalink to “学习路径建议”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>第一阶段：数据结构基础（1-2 周）</span></span>
<span class="line"><span>→ 数组：连续内存、随机访问、缓存友好的本质</span></span>
<span class="line"><span>→ 链表：指针操作、头插/尾插、双向链表的妙用</span></span>
<span class="line"><span>→ 栈与队列：FILO/FIFO、应用（括号匹配、单调栈、滑窗）</span></span>
<span class="line"><span>→ 哈希表：哈希冲突（拉链法 vs 开放寻址）、扩容与缩容</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第二阶段：树结构与算法（1-2 周）</span></span>
<span class="line"><span>→ 二叉树遍历：前/中/后序，递归与迭代</span></span>
<span class="line"><span>→ BST：查找、插入、删除，平衡的重要性</span></span>
<span class="line"><span>→ 堆：Top-K、优先级队列、手写大根堆/小根堆</span></span>
<span class="line"><span>→ 图：DFS/BFS、邻接表 vs 邻接矩阵</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第三阶段：核心算法思想（2-3 周）</span></span>
<span class="line"><span>→ 排序算法：快排（ partition 思想）、归并（并归思想）、堆排</span></span>
<span class="line"><span>→ 二分查找：变形题（旋转数组、寻找左边界/右边界）</span></span>
<span class="line"><span>→ 回溯：八皇后、全排列、子集</span></span>
<span class="line"><span>→ 动态规划：状态定义、状态转移、空间优化</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第四阶段：面试实战与总结（持续）</span></span>
<span class="line"><span>→ 高频面试题分类突破</span></span>
<span class="line"><span>→ 常见陷阱：边界条件、溢出、空指针</span></span>
<span class="line"><span>→ 复杂度分析：最好/最坏/平均/均摊</span></span>
<span class="line"><span>→ 工程思维：什么场景用什么数据结构</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br></div></div><h2 id="为什么面试必考算法" tabindex="-1">为什么面试必考算法？ <a class="header-anchor" href="#为什么面试必考算法" aria-label="Permalink to “为什么面试必考算法？”">​</a></h2><p>很多人抱怨「工作中又不用手写红黑树」，这话没错，但面试考算法，考的从来不是「你会不会用」，而是：</p><p><strong>第一，思维能力的筛选。</strong> 算法题本质上是在短时间内考察你分析问题、拆解问题、寻找最优解的能力。一个能在压力下保持逻辑清晰的人，大概率也能处理复杂的业务问题。</p><p><strong>第二，基础是否扎实。</strong> 你说精通 Java，但连数组和链表的插入复杂度都说不清楚，这显然不可信。算法是检验计算机基础最直接的方式。</p><p><strong>第三，工程能力的预兆。</strong> 写出的代码是否注意边界条件？是否考虑了性能？命名是否清晰？注释是否到位？一道算法题，能看出一个人的工程素养。</p><h2 id="面试的核心逻辑" tabindex="-1">面试的核心逻辑 <a class="header-anchor" href="#面试的核心逻辑" aria-label="Permalink to “面试的核心逻辑”">​</a></h2><p>算法面试分为三个层次：</p><p><strong>第一层：能做出来</strong></p><ul><li>能想到用哈希表优化查询</li><li>能写出正确的递归/迭代代码</li><li>能分析出时空复杂度</li></ul><p><strong>第二层：做得好</strong></p><ul><li>代码简洁，没有冗余分支</li><li>空间复杂度尽可能优化（原地算法）</li><li>能讲清楚「为什么这样做」</li><li>能快速想到多种解法并比较优劣</li></ul><p><strong>第三层：举一反三</strong></p><ul><li>能联系到其他相似题型</li><li>能抽象出通用解题模板</li><li>能发现面试官追问的方向</li></ul><blockquote><p>&quot;刷题不是目的，理解是。背答案的人遇到变形题就懵，真正理解的人看到新题也能找到思路。&quot;</p></blockquote>`,24)])])}const u=n(e,[["render",r]]);export{h as __pageData,u as default};
